(206, 'elementor_remote_info_feed_data', 'a:3:{i:0;a:5:{s:5:\"title\";s:81:\"Introducing Platinum Support: Your Ultimate Solution for Superior Website Support\";s:7:\"excerpt\";s:149:\"Introducing Platinum Support: Elevate your Elementor experience with dedicated expert assistance, faster response times, and 24/7 real human support.\";s:7:\"created\";i:1723108567;s:5:\"badge\";s:3:\"NEW\";s:3:\"url\";s:128:\"https://elementor.com/blog/introducing-platinum-support/?utm_source=wp-overview-widget&utm_medium=wp-dash&utm_campaign=news-feed\";}i:1;a:5:{s:5:\"title\";s:64:\"Image Optimizer 1.5: Introducing AVIF Compression and Conversion\";s:7:\"excerpt\";s:165:\"Upgrade to Image Optimizer v1.5 and experience the power of AVIF, the next-gen image format that delivers better compression, smaller file sizes, and higher quality.\";s:7:\"created\";i:1722327900;s:5:\"badge\";s:3:\"NEW\";s:3:\"url\";s:116:\"https://elementor.com/blog/introducing-avif/?utm_source=wp-overview-widget&utm_medium=wp-dash&utm_campaign=news-feed\";}i:2;a:5:{s:5:\"title\";s:57:\"New Off-Canvas Widget & Element Caching in Elementor 3.22\";s:7:\"excerpt\";s:147:\"Build Interactive Layouts with the Off-Canvas Widget and Give Your Websites a Major Performance Improvement by Activating Element Caching and More!\";s:7:\"created\";i:1718720040;s:5:\"badge\";s:3:\"NEW\";s:3:\"url\";s:140:\"https://elementor.com/blog/elementor-322-off-canvas-element-caching/?utm_source=wp-overview-widget&utm_medium=wp-dash&utm_campaign=news-feed\";}}', 'off'),
